ALTER TABLE admin_settings_audit_logs
    ADD COLUMN IF NOT EXISTS effective_date DATE,
    ADD COLUMN IF NOT EXISTS change_impact VARCHAR(1000),
    ADD COLUMN IF NOT EXISTS approval_status VARCHAR(80) NOT NULL DEFAULT 'Not Required';

CREATE INDEX IF NOT EXISTS ix_admin_settings_audit_org_section_ts
    ON admin_settings_audit_logs (organization_id, section, utc_timestamp DESC);
